export async function pushDoc(db, api, id) {
  const doc = await db.get('reports', id);
  const res = await api.put(`/reports/${id}`, {
    body: doc, // whole doc, single updatedAt
    ifMatch: doc.rev,
  });
  if (res.status === 409) {
    const server = await api.get(`/reports/${id}`);
    // naive: newest wins, clobbers other device's fields
    if (server.updatedAt > doc.updatedAt) {
      await db.put('reports', server);
    } else {
      await api.put(`/reports/${id}`, { body: doc, force: true });
    }
  }
}

export const schema = {
  reports: { keyPath: 'id', value: { id:'', rev:0, updatedAt:0, fields:{} } },
};
// no per-field versioning, no causal metadata

// Hybrid Logical Clock: monotonic across skew
export type HLC = { wall: number; counter: number; node: string };
let last: HLC = { wall: 0, counter: 0, node: '' };
export function initHlc(node: string) { last = { wall: 0, counter: 0, node }; }
export function now(): HLC {
  const phys = Date.now();
  if (phys > last.wall) last = { wall: phys, counter: 0, node: last.node };
  else last = { wall: last.wall, counter: last.counter + 1, node: last.node };
  return { ...last };
}
export function receive(remote: HLC): void {
  const phys = Date.now();
  const wall = Math.max(phys, last.wall, remote.wall);
  let counter = 0;
  if (wall === last.wall && wall === remote.wall) counter = Math.max(last.counter, remote.counter) + 1;
  else if (wall === last.wall) counter = last.counter + 1;
  else if (wall === remote.wall) counter = remote.counter + 1;
  last = { wall, counter, node: last.node };
}
export function gt(a: HLC, b: HLC): boolean {
  if (a.wall !== b.wall) return a.wall > b.wall;
  if (a.counter !== b.counter) return a.counter > b.counter;
  return a.node > b.node; // deterministic tiebreak
}

import { HLC, gt } from './hlc';
export type Reg<T> = { v: T; t: HLC };
export function mergeReg<T>(a: Reg<T> | undefined, b: Reg<T> | undefined): Reg<T> | undefined {
  if (!a) return b; if (!b) return a;
  return gt(a.t, b.t) ? a : b;
}
export type DocCrdt = { id: string; fields: Record<string, Reg<unknown>> };
export function mergeDoc(a: DocCrdt, b: DocCrdt): DocCrdt {
  const keys = new Set([...Object.keys(a.fields), ...Object.keys(b.fields)]);
  const fields: Record<string, Reg<unknown>> = {};
  for (const k of keys) fields[k] = mergeReg(a.fields[k], b.fields[k])!;
  return { id: a.id, fields };
}

import { mergeDoc, DocCrdt } from '../crdt/register';
import { now, receive } from '../crdt/hlc';
export async function pushDoc(db, api, id: string) {
  const local: DocCrdt = await db.get('reports', id);
  const dirty = Object.fromEntries(Object.entries(local.fields).filter(([,r]:any)=>r.dirty));
  if (Object.keys(dirty).length === 0) return;
  const res = await api.post(`/reports/${id}/merge`, { body: { id, fields: dirty } });
  receive(res.body.maxHlc);
  const merged = mergeDoc(local, res.body); // commutative; safe to reapply
  for (const k of Object.keys(merged.fields)) (merged.fields[k] as any).dirty = false;
  await db.put('reports', merged);
}

import { mergeDoc, DocCrdt } from '../src/crdt/register';
export async function handleMerge(store, id: string, incoming: DocCrdt) {
  return store.transaction(async (tx) => {
    const current: DocCrdt = (await tx.get(id)) ?? { id, fields: {} };
    const merged = mergeDoc(current, incoming);
    await tx.put(id, merged); // idempotent under retries
    const maxHlc = Object.values(merged.fields).reduce((m:any,r:any)=> (!m||r.t.wall>m.wall)?r.t:m, null);
    return { ...merged, maxHlc };
  });
}

self.addEventListener('sync', (e) => {
  if (e.tag === 'order-queue') e.waitUntil(flush());
});
async function flush() {
  const db = await openDB();
  const orders = await db.getAll('outbox');
  for (const o of orders) {
    await fetch('/api/orders', { method: 'POST', body: JSON.stringify(o) });
    await db.delete('outbox', o.id); // if SW dies before this -> replay -> double charge
  }
}

export default async function handler(req, res) {
  const order = req.body;
  const charge = await payments.charge(order.amount, order.card);
  const row = await db.orders.insert({ ...order, chargeId: charge.id });
  res.json({ id: row.id });
}
// no dedup; every POST charges

self.addEventListener('sync', (e) => {
  if (e.tag === 'order-queue') e.waitUntil(flush());
});
async function flush() {
  const db = await openDB();
  const tx = db.transaction('outbox', 'readwrite');
  const orders = await tx.store.index('status').getAll('pending');
  for (const o of orders) {
    await db.put('outbox', { ...o, status: 'inflight' }); // claim
    const res = await fetch('/api/orders', {
      method: 'POST',
      headers: { 'Idempotency-Key': o.idemKey, 'Content-Type': 'application/json' },
      body: JSON.stringify(o.payload),
    });
    if (res.ok) await db.delete('outbox', o.id);
    else if (res.status >= 500) await db.put('outbox', { ...o, status: 'pending' }); // retry later
    else await db.put('outbox', { ...o, status: 'dead', error: await res.text() });
  }
}

export async function enqueueOrder(db, payload) {
  const idemKey = crypto.randomUUID();
  await db.add('outbox', { id: idemKey, idemKey, payload, status: 'pending', createdAt: Date.now() });
  const reg = await navigator.serviceWorker.ready;
  await reg.sync.register('order-queue');
  return idemKey;
}

export default async function handler(req, res) {
  const key = req.headers['idempotency-key'];
  if (!key) return res.status(400).json({ error: 'missing idempotency key' });
  const result = await db.tx(async (t) => {
    const prior = await t.idempotency.find(key);
    if (prior) return prior.response; // replay -> same result, no second charge
    const charge = await payments.charge(req.body.amount, req.body.card, { idempotencyKey: key });
    const row = await t.orders.insert({ ...req.body, chargeId: charge.id });
    const response = { id: row.id, chargeId: charge.id };
    await t.idempotency.insert({ key, response }); // unique(key) enforces exactly-once across 4 pods
    return response;
  });
  res.json(result);
}

CREATE TABLE idempotency (
  key UUID PRIMARY KEY,
  response JSONB NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now()
);
CREATE INDEX ON idempotency (created_at);
-- TTL sweep keeps table bounded

export function openDB() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open('intake', 7); // bumped from 3, no migration
    req.onupgradeneeded = (e) => {
      const db = e.target.result;
      if (!db.objectStoreNames.contains('forms')) {
        db.createObjectStore('forms', { keyPath: 'id' });
      }
      // no per-version migration; renamed patientName->patient.fullName not handled
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

export async function readForm(db, id) {
  const f = await db.get('forms', id);
  return { name: f.patient.fullName.trim() }; // throws on legacy rows: patient is undefined
}

export type Migration = { version: number; up: (tx: IDBTransaction) => Promise<void> };
function cursorEach(store: IDBObjectStore, fn: (v: any) => any): Promise<void> {
  return new Promise((resolve, reject) => {
    const req = store.openCursor();
    req.onsuccess = () => {
      const cur = req.result;
      if (!cur) return resolve();
      const next = fn(cur.value);
      if (next !== undefined) cur.update(next);
      cur.continue();
    };
    req.onerror = () => reject(req.error);
  });
}
export const migrations: Migration[] = [
  { version: 4, up: async (tx) => {
      const s = tx.objectStore('forms');
      await cursorEach(s, (v) => ({ ...v, patient: { fullName: v.patientName ?? '' }, patientName: undefined }));
    } },
  { version: 5, up: async (tx) => {
      const s = tx.objectStore('forms');
      await cursorEach(s, (v) => ({ ...v, schemaV: 5 }));
    } },
  { version: 6, up: async (tx) => { tx.objectStore('forms').createIndex('byStatus', 'status'); } },
  { version: 7, up: async (tx) => {
      const s = tx.objectStore('forms');
      await cursorEach(s, (v) => v.patient?.fullName ? v : { ...v, patient: { fullName: '' } });
    } },
];

import { migrations } from './migrations';
export function openDB(): Promise<IDBDatabase> {
  const target = Math.max(...migrations.map(m => m.version));
  return new Promise((resolve, reject) => {
    const req = indexedDB.open('intake', target);
    req.onupgradeneeded = (e: any) => {
      const db = req.result; const tx = req.transaction!;
      if (!db.objectStoreNames.contains('forms')) db.createObjectStore('forms', { keyPath: 'id' });
      const from = e.oldVersion;
      // run every migration > oldVersion in order, inside this single tx
      (async () => {
        for (const m of migrations.filter(x => x.version > from).sort((a,b)=>a.version-b.version)) {
          await m.up(tx);
        }
      })().catch((err) => tx.abort()); // any failure rolls back the whole upgrade
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
    req.onblocked = () => console.warn('intake upgrade blocked by another tab');
  });
}

export async function readForm(db, id) {
  const f = await db.get('forms', id);
  if (!f) return null;
  return { name: (f.patient?.fullName ?? '').trim() }; // shape guaranteed by migration, defensive anyway
}

// single source of truth so code and migrations never disagree on target version
import { migrations } from '../migrations';
export const DB_VERSION = Math.max(...migrations.map(m => m.version));

export async function pullRoute(db, api, routeId) {
  const stops = await api.get(`/routes/${routeId}/stops`); // full 4MB every time
  await db.clear('stops');
  for (const s of stops) await db.put('stops', s);
}

export default async (req,res)=>{
  const rows = await db.stops.where({ routeId: req.params.routeId });
  res.json(rows); // no since filter, no tombstones
}

export default async (req,res)=>{
  const { routeId } = req.params;
  const cursor = Number(req.query.cursor || 0);
  const limit = 500;
  const rows = await db.query(
    `SELECT id, payload, change_seq, deleted FROM stops
     WHERE route_id=$1 AND change_seq > $2
     ORDER BY change_seq ASC LIMIT $3`, [routeId, cursor, limit]);
  const next = rows.length ? rows[rows.length-1].change_seq : cursor;
  res.json({ rows, nextCursor: next, hasMore: rows.length === limit });
}

ALTER TABLE stops ADD COLUMN change_seq BIGINT;
ALTER TABLE stops ADD COLUMN deleted BOOLEAN DEFAULT false;
CREATE SEQUENCE stops_change_seq;
CREATE INDEX idx_stops_route_seq ON stops(route_id, change_seq);
CREATE OR REPLACE FUNCTION bump_seq() RETURNS trigger AS $$
BEGIN NEW.change_seq := nextval('stops_change_seq'); RETURN NEW; END $$ LANGUAGE plpgsql;
CREATE TRIGGER trg_stops_seq BEFORE INSERT OR UPDATE ON stops
  FOR EACH ROW EXECUTE FUNCTION bump_seq();

export async function pullDelta(db, api, routeId) {
  let cursor = (await db.get('cursors', routeId))?.seq || 0;
  let hasMore = true;
  while (hasMore) {
    const { rows, nextCursor, hasMore: more } = await api.get(
      `/routes/${routeId}/stops?cursor=${cursor}`);
    const tx = db.transaction(['stops','cursors'],'readwrite');
    for (const r of rows) {
      if (r.deleted) await tx.objectStore('stops').delete(r.id);
      else await tx.objectStore('stops').put({ id: r.id, ...r.payload, _seq: r.change_seq });
    }
    await tx.objectStore('cursors').put({ routeId, seq: nextCursor });
    await tx.done; cursor = nextCursor; hasMore = more;
  }
}

// never overwrite a row that has unsynced local edits
export function shouldApply(local, remote){
  if (local && local._dirty) return remote._seq > (local._baseSeq ?? 0);
  return true;
}

const SHELL = 'shell-v1';
self.addEventListener('fetch', (e) => {
  const url = new URL(e.request.url);
  if (e.request.mode === 'navigate') {
    e.respondWith((async () => {
      const cache = await caches.open(SHELL);
      const cached = await cache.match('/index.html');
      const network = fetch('/index.html').then(r => { cache.put('/index.html', r.clone()); return r; });
      return cached || network; // serves stale HTML referencing dead chunk hashes
    })());
  }
});

const BUILD = self.__BUILD_ID__; // injected at build time
const SHELL = `shell-${BUILD}`;
self.addEventListener('install', (e) => {
  e.waitUntil((async () => {
    const cache = await caches.open(SHELL);
    await cache.addAll(self.__PRECACHE__); // hashed chunks for THIS build, atomic
  })());
});
self.addEventListener('activate', (e) => {
  e.waitUntil((async () => {
    const keys = await caches.keys();
    await Promise.all(keys.filter(k => k.startsWith('shell-') && k !== SHELL).map(k => caches.delete(k)));
    await self.clients.claim();
  })());
});
self.addEventListener('fetch', (e) => {
  if (e.request.mode === 'navigate') {
    e.respondWith((async () => {
      const cache = await caches.open(SHELL);
      try {
        const net = await Promise.race([fetch(e.request), new Promise((_,r)=>setTimeout(()=>r('t'),2500))]);
        cache.put('/index.html', net.clone()); return net;
      } catch { return (await cache.match('/index.html')) || Response.error(); }
    })());
  }
});

export const BUILD_ID = (window as any).__BUILD_ID__ as string;
export function shellMatchesAssets(): boolean {
  return document.querySelector('meta[name=build-id]')?.getAttribute('content') === BUILD_ID;
}

import { BUILD_ID } from './buildId';
let healed = sessionStorage.getItem('chunk-healed') === BUILD_ID;
function loadApp(){
  return import('./App').then(({ App }) => render(App)).catch((err) => {
    if (/ChunkLoadError/.test(String(err)) && !healed) {
      sessionStorage.setItem('chunk-healed', BUILD_ID);
      navigator.serviceWorker.getRegistration().then(r => r?.update());
      location.reload(); // exactly once per build
    } else throw err;
  });
}
loadApp();

// webpack/vite plugin: stamp BUILD_ID into index.html, sw, and the precache manifest
module.exports = function inject({ assets }) {
  const id = process.env.GIT_SHA;
  return { __BUILD_ID__: id, __PRECACHE__: assets.filter(a => /\.(js|css)$/.test(a)).map(a => '/'+a) };
};

export async function pushCount(api, sku, qty){
  await api.put(`/inventory/${sku}`, { qty, at: Date.now() }); // last writer wins
}

export default async (req,res)=>{
  await db.inventory.update(req.params.sku, { qty: req.body.qty });
  res.json({ ok: true });
}

export type VV = Record<string, number>;
export function bump(vv: VV, node: string): VV { return { ...vv, [node]: (vv[node]||0)+1 }; }
export function compare(a: VV, b: VV): 'eq'|'lt'|'gt'|'concurrent' {
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);
  let lt=false, gt=false;
  for (const k of keys){ const x=a[k]||0, y=b[k]||0; if(x<y)lt=true; if(x>y)gt=true; }
  if(lt&&gt) return 'concurrent'; if(lt) return 'lt'; if(gt) return 'gt'; return 'eq';
}
export function mergeVV(a: VV, b: VV): VV {
  const out: VV = { ...a };
  for (const k of Object.keys(b)) out[k] = Math.max(out[k]||0, b[k]);
  return out;
}

import { bump } from './vectorClock';
export async function pushCount(db, api, sku, qty, node){
  const local = (await db.get('counts', sku)) || { sku, qty:0, vv:{} };
  const vv = bump(local.vv, node);
  await db.put('counts', { sku, qty, vv });
  const res = await api.put(`/inventory/${sku}`, { qty, vv, node });
  if (res.conflict) await db.put('conflicts', { sku, ...res });
}

const { compare, mergeVV } = require('../src/count/vectorClock');
export default async (req,res)=>{
  const { sku } = req.params; const { qty, vv } = req.body;
  await db.tx(async (t)=>{
    const cur = (await t.inventory.find(sku)) || { qty:0, vv:{} };
    const rel = compare(vv, cur.vv);
    if (rel==='gt' || rel==='eq') {
      await t.inventory.upsert(sku, { qty, vv: mergeVV(cur.vv, vv) });
      res.json({ ok:true, applied:true });
    } else if (rel==='lt') {
      res.json({ ok:true, applied:false, stale:true, qty: cur.qty });
    } else {
      await t.conflicts.insert({ sku, candidates:[{qty:cur.qty,vv:cur.vv},{qty,vv}], at:new Date() });
      res.json({ ok:true, conflict:true, sku });
    }
  });
}

