let pending: any[] = [];
export function enqueue(m){ pending.push(m); }
setInterval(async () => {
  if (!navigator.onLine) return;
  for (const m of pending) {
    await fetch(m.url, { method:'POST', body: JSON.stringify(m.body) });
  }
  pending = []; // wipes even failures; no backoff
}, 5000);

import { openDB } from 'idb';
export const qdb = openDB('mutq', 1, { upgrade(db){
  const s = db.createObjectStore('queue', { keyPath: 'seq', autoIncrement: true });
  s.createIndex('entity', 'entity'); s.createIndex('state', 'state');
  db.createObjectStore('dead', { keyPath: 'seq' });
}});

import { qdb } from './db';
import { withFreshToken } from '../auth';
let draining = false;
function backoff(attempt){ return Math.min(60000, 1000*2**attempt) * (0.5 + Math.random()); }
export async function drain(){
  if (draining || !navigator.onLine) return; draining = true;
  try {
    const db = await qdb;
    const items = (await db.getAllFromIndex('queue','state','pending')).sort((a,b)=>a.seq-b.seq);
    for (const m of items) {
      if (Date.now()-m.createdAt > 72*3600e3){ await deadLetter(db,m); continue; }
      try {
        const res = await withFreshToken(t => fetch(m.url,{ method:m.method, headers:{Authorization:`Bearer ${t}`,'Content-Type':'application/json'}, body: JSON.stringify(m.body) }));
        if (res.ok) await db.delete('queue', m.seq);
        else if (res.status>=500) { await schedule(db,m); break; } // stop run, backoff
        else await deadLetter(db,m); // 4xx (non-401) is permanent
      } catch { await schedule(db,m); break; }
    }
  } finally { draining = false; }
}
async function schedule(db,m){ const a=(m.attempt||0)+1; await db.put('queue',{...m,attempt:a,nextAt:Date.now()+backoff(a)}); setTimeout(drain, backoff(a)); }
async function deadLetter(db,m){ await db.put('dead',{...m,deadAt:Date.now()}); await db.delete('queue',m.seq); notifyUser(m); }

let token = localStorage.getItem('tok');
export async function withFreshToken(fn){
  let res = await fn(token);
  if (res.status === 401){ token = await refresh(); localStorage.setItem('tok', token); res = await fn(token); }
  return res;
}
async function refresh(){ const r = await fetch('/auth/refresh',{method:'POST'}); return (await r.json()).token; }

import { qdb } from './db';
export async function enqueue(entity, url, method, body){
  const db = await qdb;
  await db.add('queue', { entity, url, method, body, state:'pending', attempt:0, createdAt: Date.now() });
  window.addEventListener('online', drainOnce, { once:true });
  drain();
}
function drainOnce(){ import('./drain').then(m=>m.drain()); }

setInterval(async () => {
  const rows = await api.get('/opportunities?since='+last);
  for (const r of rows) await db.put('opps', r); // blind overwrite of dirty locals
  last = Date.now();
}, 30000);

export async function sync(db, api){
  await push(db, api);
  await pull(db, api);
}
async function push(db, api){
  const dirty = await db.getAllFromIndex('opps','dirty', 1);
  for (const row of dirty){
    const res = await api.put(`/opportunities/${row.id}`, { base: row.baseRev, patch: row.patch });
    if (res.status === 200) await db.put('opps', { ...row, rev: res.rev, baseRev: res.rev, dirty: 0, patch: {} });
    else if (res.status === 409) await db.put('opps', { ...row, conflict: res.server }); // surface
  }
}
async function pull(db, api){
  let cursor = (await db.get('meta','oppCursor'))?.v || 0;
  const { rows, nextCursor } = await api.get(`/opportunities/delta?cursor=${cursor}`);
  const tx = db.transaction(['opps','meta'],'readwrite');
  for (const r of rows){
    const local = await tx.objectStore('opps').get(r.id);
    if (local?.dirty) continue; // never overwrite unsynced edits
    if (local && local.rev === r.rev) continue; // already have it (echoed push)
    await tx.objectStore('opps').put({ ...r, dirty: 0, baseRev: r.rev });
  }
  await tx.objectStore('meta').put({ k:'oppCursor', v: nextCursor });
  await tx.done;
}

export default async (req,res)=>{
  const { id } = req.params; const { base, patch } = req.body;
  await db.tx(async (t)=>{
    const cur = await t.opps.find(id);
    if (cur.rev !== base) return res.status(409).json({ server: cur }); // concurrent server edit
    const merged = { ...cur, ...patch, rev: cur.rev + 1 };
    await t.opps.update(id, merged);
    res.json({ status: 200, rev: merged.rev });
  });
}

import { sync } from './engine';
let timer; 
self.onmessage = (e) => { if (e.data === 'start'){ tick(); } };
async function tick(){
  try { await sync(self.db, self.api); } catch (e) { /* keep cursor, retry */ }
  timer = setTimeout(tick, navigator.onLine ? 15000 : 60000);
}

// add dirty index + baseRev for two-phase reconcile
export function upgrade(db){
  const s = db.objectStoreNames.contains('opps') ? null : db.createObjectStore('opps',{keyPath:'id'});
  const store = s || db.transaction('opps').objectStore('opps');
  if (!store.indexNames.contains('dirty')) store.createIndex('dirty','dirty');
}

const chan = new BroadcastChannel('sync');
export function startSync(db, api){
  navigator.locks.request('sync-leader', { mode: 'exclusive' }, async (lock) => {
    // held until this tab/promise ends; only one tab reaches here
    while (true) {
      const applied = await runSync(db, api); // returns deltas applied
      if (applied.length) chan.postMessage({ type:'delta', applied });
      await sleep(navigator.onLine ? 8000 : 30000);
    }
  });
}
chan.onmessage = (e) => { if (e.data.type==='delta') applyToCache(e.data.applied); };

export async function runSync(db, api){
  // cursor + dirty claim live in IndexedDB so a failover leader resumes safely
  const claim = await claimDirty(db); // marks rows inflight in a tx (atomic)
  const pushed = await pushClaimed(db, api, claim);
  const pulled = await pullDelta(db, api);
  return [...pushed, ...pulled];
}
async function claimDirty(db){
  const tx = db.transaction('opps','readwrite');
  const dirty = await tx.store.index('dirty').getAll(1);
  for (const r of dirty) if (!r.inflight) await tx.store.put({ ...r, inflight: Date.now() });
  await tx.done; return dirty.filter(r=>!r.inflight);
}

// reclaim rows whose inflight is stale (previous leader died mid-push)
export async function reclaimStale(db, api){
  const tx = db.transaction('opps','readwrite');
  const all = await tx.store.index('dirty').getAll(1);
  for (const r of all) if (r.inflight && Date.now()-r.inflight > 30000)
    await tx.store.put({ ...r, inflight: 0 }); // requeue; idempotency key on server dedups
  await tx.done;
}

