async function serveAudio(req){
  const cache = await caches.open('audio-v1');
  const full = await cache.match(req.url, { ignoreVary: true });
  if (!full) return fetch(req);
  const buf = await full.arrayBuffer();
  const range = req.headers.get('Range');
  if (!range) return new Response(buf, { headers: { 'Content-Type':'audio/mpeg', 'Accept-Ranges':'bytes' } });
  const m = /bytes=(\d+)-(\d*)/.exec(range);
  const start = Number(m[1]); const end = m[2] ? Number(m[2]) : buf.byteLength - 1;
  const slice = buf.slice(start, end + 1);
  return new Response(slice, { status: 206, headers: {
    'Content-Type':'audio/mpeg', 'Accept-Ranges':'bytes',
    'Content-Range': `bytes ${start}-${end}/${buf.byteLength}`,
    'Content-Length': String(slice.byteLength) } });
}

export async function downloadLesson(id, url, onProgress){
  const cache = await caches.open('audio-v1');
  const existing = await cache.match(url);
  let from = 0;
  if (existing){ const meta = await getMeta(id); from = meta?.bytes || 0; if (meta?.complete) return; }
  const res = await fetch(url, from ? { headers: { Range: `bytes=${from}-` } } : {});
  const total = Number(res.headers.get('Content-Range')?.split('/')[1] || res.headers.get('Content-Length'));
  const chunks = existing ? [await existing.arrayBuffer()] : [];
  const reader = res.body.getReader(); let got = from;
  for(;;){ const { done, value } = await reader.read(); if (done) break; chunks.push(value); got += value.length; await setMeta(id,{bytes:got}); onProgress(got/total); }
  await cache.put(url, new Response(new Blob(chunks)));
  await setMeta(id, { bytes: got, complete: true });
}

export async function ensureBudget(maxBytes = 500*1024*1024){
  const { usage } = await navigator.storage.estimate();
  if ((usage||0) < maxBytes) return;
  const meta = await listMetaByLastPlayed(); // LRU
  const cache = await caches.open('audio-v1');
  let freed = 0;
  for (const m of meta){ await cache.delete(m.url); await delMeta(m.id); freed += m.bytes; if ((usage-freed) < maxBytes*0.8) break; }
}

