export async function apply(db, ops){
  const deferred = [];
  const sorted = ops.sort((a,b)=> a.seq - b.seq);
  for (const op of sorted){
    const existing = await db.get('posts', op.id);
    if (existing?.tombstone && op.seq <= existing.seq) continue; // terminal: ignore stale resurrect
    if (op.deps && !(await depsSatisfied(db, op.deps))) { deferred.push(op); continue; }
    if (op.type==='delete') await db.put('posts', { id: op.id, tombstone: true, seq: op.seq });
    else if (!existing?.tombstone || op.seq > existing.seq) await db.put('posts', { ...op.doc, seq: op.seq });
  }
  if (deferred.length) await db.put('deferred', { ops: deferred }); // retry when deps arrive
}
