import { sha256hex } from './hash';
export type Node = { hash: string; children?: Node[]; key?: string };
export function buildMerkle(partitions: Record<string,unknown>): Node {
  const leaves = Object.keys(partitions).sort().map(k => ({ key:k, hash: sha256hex(JSON.stringify(partitions[k])) }));
  return reduce(leaves);
}
function reduce(nodes: Node[]): Node {
  if (nodes.length === 1) return nodes[0];
  const next: Node[] = [];
  for (let i=0;i<nodes.length;i+=2){ const pair = nodes.slice(i,i+2); next.push({ hash: sha256hex(pair.map(n=>n.hash).join('')), children: pair }); }
  return reduce(next);
}
export function diffLeaves(a: Node, b: Node, out: string[] = []): string[] {
  if (a.hash === b.hash) return out;
  if (!a.children || !b.children){ if (a.key) out.push(a.key); return out; }
  for (let i=0;i<Math.max(a.children.length,b.children.length);i++) diffLeaves(a.children[i]||a, b.children[i]||b, out);
  return out;
}

import { buildMerkle, diffLeaves } from './merkle';
