export async function checkpoint(db, api, matchId){
  const local = buildMerkle(await partitionState(db, matchId));
  const { root: serverRoot } = await api.get(`/match/${matchId}/merkle-root`);
  if (local.hash === serverRoot) return { ok: true };
  // descend: ask server for its tree level-by-level, diff, fetch only diverged leaves
  const serverTree = await api.get(`/match/${matchId}/merkle-tree`);
  const bad = diffLeaves(local, serverTree);
  const leaves = await api.post(`/match/${matchId}/leaves`, { keys: bad });
  await applyAuthoritativeLeaves(db, matchId, leaves); // targeted repair
  return { ok: true, repaired: bad };
}

