export const CANONICAL = 5;
const upcasters = {
  3: (e) => ({ ...e, location: { lat:e.lat, lng:e.lng }, lat:undefined, lng:undefined }), // v3->v4 fields
  4: (e) => ({ ...e, assignee: typeof e.assignee==='string' ? { id:e.assignee } : e.assignee }), // v4->v5 shape
};
export function upcast(e, from){ let cur = { ...e }; for (let v=from; v<CANONICAL; v++){ if (upcasters[v]) cur = upcasters[v](cur); } return cur; }
const downcasters = {
  4: (e) => ({ ...e, lat:e.location.lat, lng:e.location.lng, location:undefined }),
  3: (e) => ({ ...e, assignee: e.assignee.id }),
};
export function downcast(e, to){ let cur = { ...e }; for (let v=CANONICAL-1; v>=to; v--){ if (downcasters[v]) cur = downcasters[v](cur); } return cur; }

