func (s *Server) Sync(ctx context.Context, req *pb.SyncReq) (*pb.SyncResp, error) {
    tasks := s.store.AllTasks(req.UserId) // full snapshot every time
    notifyAll(req.UserId)                 // spurious fan-out
    return &pb.SyncResp{Tasks: tasks}, nil
}

type Op struct { Pos uint64; Type string; TaskID string; Patch []byte; Hash string }
func (l *Log) Append(userID string, op Op) (uint64, error) {
    return l.store.Tx(func(tx *Tx) (uint64, error) {
        pos := tx.NextPos(userID) // monotonic per user
        op.Pos = pos
        if err := tx.AppendOp(userID, op); err != nil { return 0, err }
        return pos, nil
    })
}
func (l *Log) Since(userID string, from uint64, limit int) ([]Op, error) {
    return l.store.OpsSince(userID, from, limit) // paged catch-up
}

func (s *Server) StreamOps(req *pb.StreamReq, stream pb.Sync_StreamOpsServer) error {
    // 1) catch-up from req.From
    for {
        ops, err := s.log.Since(req.UserId, req.From, 500)
        if err != nil { return err }
        for _, op := range ops { if err := stream.Send(toPb(op)); err != nil { return err }; req.From = op.Pos }
        if len(ops) < 500 { break }
    }
    // 2) live tail
    sub := s.bus.Subscribe(req.UserId)
    defer sub.Close()
    for op := range sub.C { if op.Pos > req.From { _ = stream.Send(toPb(op)) } }
    return nil
}

func (c *Compactor) Run(userID string) error {
    minPos := c.bus.MinClientPos(userID) // lowest position any active client has acked
    snap, upto := c.fold(userID, minPos)  // materialize tasks from ops <= minPos
    return c.store.Tx(func(tx *Tx) (uint64, error) {
        if err := tx.PutSnapshot(userID, snap, upto); err != nil { return 0, err }
        return 0, tx.TruncateOpsBelow(userID, upto) // safe: every client already past it
    })
}

