// topological drain: parents before children, by recorded dependsOn
export async function drain(db, api){
  const items = await db.getAll('outbox');
  const ordered = topoSort(items); // edges from dependsOn temp ids
  for (const item of ordered){
    const refs = await resolveRefs(db, item); // map temp parent ids -> server ids
    const res = await api.post(item.url, { ...item.payload, ...refs, idemKey: item.idemKey });
    if (res.ok){
      if (isTemp(item.localId)) await mapId(db, item.localId, res.id);
      await rewriteLocal(db, item.localId, res.id);
      await db.delete('outbox', item.id);
    } else if (res.status >= 500) break; // retry later, order preserved
  }
}

export async function rewriteLocal(db, tempId, realId){
  if (!isTemp(tempId)) return;
  const tx = db.transaction(['companies','contacts','notes'],'readwrite');
  // rewrite the entity's own id and any children pointing at it
  for (const store of ['contacts','notes']){
    const idx = tx.objectStore(store).index('companyId');
    let cur = await idx.openCursor(tempId);
    while (cur){ await cur.update({ ...cur.value, companyId: realId }); cur = await cur.continue(); }
  }
  const self = await tx.objectStore('companies').get(tempId);
  if (self){ await tx.objectStore('companies').delete(tempId); await tx.objectStore('companies').put({ ...self, id: realId, _local:false }); }
  await tx.done;
}

