import { evictLRU } from './evict';
export async function cacheListing(db, listing){
  // 1) critical text first, isolated tx -> always recoverable
  await db.put('listings', { ...listing.meta, photosCached:false, lastUsed: Date.now() });
  // 2) media, guarded per-photo with eviction+retry
  for (const p of listing.photos){
    if (!(await putWithQuota(db, 'photos', p))) {
      await db.put('listings', { ...listing.meta, photosCached:false }); // degrade, keep text
      return { degraded:true };
    }
  }
  await db.put('listings', { ...listing.meta, photosCached:true, lastUsed: Date.now() });
  return { degraded:false };
}
async function putWithQuota(db, store, value){
  for (let i=0;i<2;i++){
    try { await db.put(store, value); return true; }
    catch (e:any){ if (e?.name === 'QuotaExceededError'){ await evictLRU(db, 30*1024*1024); continue; } throw e; }
  }
  return false;
}

export async function evictLRU(db, targetBytes){
  const listings = (await db.getAll('listings')).filter(l=>l.photosCached).sort((a,b)=>a.lastUsed-b.lastUsed);
  let freed = 0;
  for (const l of listings){
    const photos = await db.getAllFromIndex('photos','listingId', l.id);
    const tx = db.transaction(['photos','listings'],'readwrite');
    for (const p of photos){ freed += p.blob.size; await tx.objectStore('photos').delete(p.id); }
    await tx.objectStore('listings').put({ ...l, photosCached:false });
    await tx.done;
    if (freed >= targetBytes) break;
  }
}

