def update_recipe(request, id):
    r = Recipe.objects.get(id=id)
    r.data = request.data  # blindly stores client's merged result
    r.save()
    return JsonResponse({'ok': True})

def merge_recipe(base, current, patch):
    """Pure, deterministic 3-way merge over structured recipe fields."""
    out = dict(current)
    # scalar fields: if patch changed it from base, take patch; else keep current
    for f in ('title', 'servings'):
        if patch.get(f) != base.get(f):
            out[f] = patch.get(f)
    # tags: set union is commutative/deterministic
    out['tags'] = sorted(set(current.get('tags', [])) | set(patch.get('tags', [])))
    # steps: positional 3-way; deterministic tiebreak by stable id
    out['steps'] = merge_lists(base.get('steps', []), current.get('steps', []), patch.get('steps', []))
    return out

def merge_lists(base, cur, patch):
    by_id = {s['id']: s for s in cur}
    for s in patch:
        b = next((x for x in base if x['id'] == s['id']), None)
        if b != s:  # patch changed this step
            by_id[s['id']] = s
    return [by_id[k] for k in sorted(by_id)]

