}

export function diff(base, cur){
  const patch:any = {};
  for (const k of ['title','servings']) if (cur[k] !== base[k]) patch[k] = cur[k];
  patch.tags = cur.tags; patch.steps = cur.steps; // server reconciles against base
  return patch;
}

