export type S = 'idle'|'pushing'|'pulling'|'error'|'offline';
const transitions: Record<S, Partial<Record<string, S>>> = {
  idle:    { START:'pushing', OFFLINE:'offline' },
  pushing: { PUSH_DONE:'pulling', FAIL:'error', OFFLINE:'offline' },
  pulling: { PULL_DONE:'idle', FAIL:'error', OFFLINE:'offline' },
  error:   { RETRY:'pushing', OFFLINE:'offline' },
  offline: { ONLINE:'idle' },
};
let state: S = 'idle'; const subs = new Set<(s:S)=>void>();
export function dispatch(ev: string){
  const next = transitions[state]?.[ev];
  if (!next){ console.warn(`[sync] illegal ${ev} from ${state}`); return false; }
  console.info(`[sync] ${state} --${ev}--> ${next}`);
  state = next; subs.forEach(f=>f(state)); return true;
}
export const getState = () => state;
export function onState(fn:(s:S)=>void){ subs.add(fn); return ()=>subs.delete(fn); }

