export async function runSync(db, api){
  if (!dispatch('START')) return; // only fires from idle
  try {
    await push(db, api); dispatch('PUSH_DONE');
    await pull(db, api); dispatch('PULL_DONE'); // strictly after push
  } catch (e){ dispatch('FAIL'); }
}

import { getState, dispatch } from './machine';
let since = Date.now(); let last = getState();
setInterval(() => {
  const s = getState();
  if (s !== last){ last = s; since = Date.now(); return; }
  if ((s === 'pushing' || s === 'pulling') && Date.now()-since > 30000){
    console.warn('[sync] watchdog recovering from stuck '+s);
    dispatch('FAIL'); // -> error, then RETRY path can recover
  }
}, 5000);

