@Post('initial/session')
async start(@Req() req){
  const sessionId = randomUUID();
  await this.redis.hset(`sync:${sessionId}`, { user: req.userId, cursor: '0' });
  await this.redis.expire(`sync:${sessionId}`, 3600);
