@Get('initial/:sessionId/page')
async page(@Param('sessionId') sid){
  const sess = await this.redis.hgetall(`sync:${sid}`);
  if (!sess?.cursor) throw new NotFoundException('session expired');
  const cursor = BigInt(sess.cursor);
  // keyset: stable under concurrent inserts because we seek by immutable id
  const docs = await this.db.query('SELECT * FROM docs WHERE org=$1 AND id > $2 ORDER BY id ASC LIMIT 1000', [sess.org, cursor.toString()]);
  const next = docs.length ? docs[docs.length-1].id : sess.cursor;
  await this.redis.hset(`sync:${sid}`, { cursor: String(next) });
  await this.redis.expire(`sync:${sid}`, 3600); // sliding TTL keeps active sessions alive
  return { docs, nextCursor: next, done: docs.length < 1000 };
}

export async function initialSync(db, api){
  let sid = (await db.get('meta','syncSession'))?.v;
  if (!sid){ sid = (await api.post('/sync/initial/session')).sessionId; await db.put('meta',{k:'syncSession',v:sid}); }
  for (;;){
    let res;
    try { res = await api.get(`/sync/initial/${sid}/page`); }
    catch (e:any){ if (e.status === 404){ await db.delete('meta','syncSession'); return initialSync(db, api); } throw e; }
    const tx = db.transaction('docs','readwrite');
    for (const d of res.docs) await tx.store.put(d);
    await tx.done;
    if (res.done){ await db.delete('meta','syncSession'); break; }
  }
}

