export type ORSet = { adds: Record<string, Set<string>>; tombs: Set<string> }; // tag -> set of uids
export function add(s: ORSet, tag: string){ const uid = crypto.randomUUID(); (s.adds[tag] ??= new Set()).add(uid); }
export function remove(s: ORSet, tag: string){ for (const uid of s.adds[tag] ?? []) s.tombs.add(uid); }
export function values(s: ORSet){ return Object.keys(s.adds).filter(tag => [...(s.adds[tag])].some(uid => !s.tombs.has(uid))); }
export function merge(a: ORSet, b: ORSet): ORSet {
  const adds: Record<string, Set<string>> = {};
  for (const s of [a, b]) for (const [tag, uids] of Object.entries(s.adds)) { (adds[tag] ??= new Set()); uids.forEach(u => adds[tag].add(u)); }
  return { adds, tombs: new Set([...a.tombs, ...b.tombs]) };
}

