const { applyPatch } = require('fast-json-patch');
export default async (req,res)=>{
  const { patch, baseRev } = req.body;
  await db.tx(async (t)=>{
    const cur = await t.drafts.find(req.params.id);
    const conflicts = [];
    const apply = [];
    for (const op of patch){ const field = op.path.slice(1);
      // conflict iff the field changed on server since the client's base
      if (cur.rev !== baseRev && cur.data[field] !== cur.baseSnapshot?.[field]) conflicts.push({ field, server: cur.data[field], client: op.value });
      else apply.push(op);
    }
    if (apply.length){ applyPatch(cur.data, apply); cur.rev += 1; cur.baseSnapshot = { ...cur.data }; await t.drafts.update(req.params.id, cur); }
    res.json({ conflicts, draft: cur.data, rev: cur.rev });
  });
}

