const inflight = new Map();
self.addEventListener('fetch', (e) => {
  if (e.request.method !== 'GET') return;
  const url = new URL(e.request.url);
  if (e.request.headers.has('Authorization')) return; // never coalesce/cache user-specific
  if (/\/api\/(articles|list)/.test(url.pathname)) e.respondWith(swr(e.request));
});
async function swr(req){
  const cache = await caches.open('api-swr');
  const cached = await cache.match(req);
  const fresh = cached && (Date.now() - Number(cached.headers.get('x-cached-at')) < 60000);
  if (cached && fresh) return cached;
  const revalidate = () => coalesce(req.url, async () => {
    const res = await fetch(req); const body = await res.arrayBuffer();
    const stamped = new Response(body, { headers: new Headers([...res.headers, ['x-cached-at', String(Date.now())]]) });
    await cache.put(req, stamped.clone()); return stamped;
  });
  return cached || revalidate(); // stale returned instantly; revalidate in bg
}
function coalesce(key, fn){
  if (inflight.has(key)) return inflight.get(key);
  const p = fn().finally(() => inflight.delete(key));
  inflight.set(key, p); return p; // single-flight per URL
}

export async function evictExpired(maxEntries = 500){
  const cache = await caches.open('api-swr');
  const reqs = await cache.keys();
  if (reqs.length <= maxEntries) return;
  const dated = await Promise.all(reqs.map(async r => ({ r, at: Number((await cache.match(r)).headers.get('x-cached-at')||0) })));
  dated.sort((a,b)=>a.at-b.at);
  for (const { r } of dated.slice(0, reqs.length - maxEntries)) await cache.delete(r);
}

