  const total = req.body.items.reduce((s,i)=>s+i.price*i.qty,0); // uses client-supplied prices!
  const order = await db.orders.insert({ items:req.body.items, total });
  await payments.charge(total);
  res.json({ id: order.id });
}

export default async (req,res)=>{
  const out = { lines: [], changed: false };
  await db.tx(async (t)=>{
    for (const i of req.body.items){
      const p = await t.products.find(i.sku);
      const available = p ? p.stock : 0;
      const line = { sku:i.sku, qty:i.qty,
        livePrice: p?.price ?? null, cachedPrice: i.cachedPrice,
        priceChanged: p && p.price !== i.cachedPrice,
        inStock: available >= i.qty, available };
      if (line.priceChanged || !line.inStock) out.changed = true;
      out.lines.push(line);
    }
  });
  res.json(out); // server prices are authoritative; client prices are only compared
}

export async function checkout(api, cart, confirmDiffs){
  const recon = await api.post('/cart/reconcile', { items: cart.items });
  if (recon.changed){
    const ok = await confirmDiffs(recon.lines); // surface price/stock changes to user
    if (!ok) return { aborted:true, recon };
  }
  const idemKey = cart.idemKey ??= crypto.randomUUID();
  return api.post('/checkout/confirm', { items: cart.items.map(i=>({ sku:i.sku, qty:i.qty })), idemKey });
}

export default async (req,res)=>{
  const { idemKey, items } = req.body;
  const result = await db.tx(async (t)=>{
    const prior = await t.idempotency.find(idemKey); if (prior) return prior.response;
    let total = 0; const lines = [];
    for (const i of items){ const p = await t.products.findForUpdate(i.sku);
      if (p.stock < i.qty) throw new HttpError(409, { sku:i.sku, reason:'oos' });
      await t.products.decStock(i.sku, i.qty); total += p.price * i.qty; lines.push({ sku:i.sku, qty:i.qty, price:p.price }); }
    const charge = await payments.charge(total, { idempotencyKey: idemKey });
    const order = await t.orders.insert({ lines, total, chargeId: charge.id });
    const response = { id: order.id, total };
    await t.idempotency.insert({ key: idemKey, response });
    return response;
  });
  res.json(result);
}

export function ReconcileDialog({ lines, onConfirm, onCancel }){
  return <div>
    {lines.filter(l=>l.priceChanged).map(l=> <p key={l.sku}>{l.sku}: price {l.cachedPrice}->{l.livePrice}</p>)}
    {lines.filter(l=>!l.inStock).map(l=> <p key={l.sku}>{l.sku}: only {l.available} left</p>)}
    <button onClick={onConfirm}>Accept changes</button><button onClick={onCancel}>Cancel</button>
  </div>;
}

