let clock = Number(localStorage.getItem('lamport') || 0);
export function tick(){ clock = clock + 1; localStorage.setItem('lamport', String(clock)); return clock; }
export function observe(remote){ clock = Math.max(clock, remote) ; localStorage.setItem('lamport', String(clock)); }
export const deviceId = localStorage.getItem('did') || (localStorage.setItem('did', crypto.randomUUID()), localStorage.getItem('did'));

import { tick, observe, deviceId } from './lamport';
export async function write(api, id, value){
  const lc = tick();
  const res = await api.put(`/checkins/${id}`, { value, lamport: lc, device: deviceId });
  observe(res.lamport); // advance past server's clock
}

export default async (req,res)=>{
  const { value, lamport, device } = req.body;
  await db.tx(async (t)=>{
    const cur = await t.checkins.find(req.params.id) || { lamport: 0, device: '' };
    const incomingWins = lamport > cur.lamport || (lamport === cur.lamport && device > cur.device);
    if (incomingWins) await t.checkins.upsert(req.params.id, { value, lamport, device });
    const out = Math.max(lamport, cur.lamport);
    res.json({ lamport: out + 1, applied: incomingWins });
  });
}

