@Injectable()
export class OutboxRelay {
  async run(){
    for (;;){
      const batch = await this.db.outbox.unpublished({ limit: 500, orderBy: 'seq' });
      for (const ev of batch){
        await this.kafka.publish('approvals', ev.payload, { key: ev.aggregate, headers:{ eventId: ev.id } }); // key => per-aggregate order
        await this.db.outbox.markPublished(ev.id);
      }
      if (!batch.length) await sleep(200);
    }
  }
}

