self.addEventListener('fetch', (e) => {
  if (e.request.url.includes('/api/')) {
    e.respondWith(caches.match(e.request).then(r => r || fetch(e.request).then(res => { caches.open('api').then(c=>c.put(e.request,res.clone())); return res; })));
  }
});

self.addEventListener('fetch', (e) => {
  const url = new URL(e.request.url);
  if (!url.pathname.startsWith('/api/')) return;
  if (e.request.method !== 'GET'){ e.respondWith(fetch(e.request)); return; } // mutations: network-only
  e.respondWith(networkFirst(e.request));
});
async function networkFirst(req){
  const cache = await caches.open('api');
  try {
    let res = await fetch(req);
    if (res.status === 401){ const ok = await refreshToken(); if (ok) res = await fetch(reauth(req)); }
    if (res.ok) await cache.put(req, res.clone()); // cache ONLY 2xx
    return res; // do not cache 4xx/5xx
  } catch {
    const cached = await cache.match(req);
    return cached || new Response(JSON.stringify({ offline:true }), { status: 503 });
  }
}

async function refreshToken(){
  const r = await fetch('/auth/refresh', { method:'POST', credentials:'include' });
  if (!r.ok) return false;
  const { token } = await r.json();
  await idbSet('token', token); // shared with reauth()
  return true;
}
function reauth(req){
  const headers = new Headers(req.headers);
  // token read synchronously cached by refreshToken; attach for replay
  headers.set('Authorization', `Bearer ${currentToken}`);
  return new Request(req.url, { method:'GET', headers });
}

