type State = 'closed'|'open'|'half';
let state: State = 'closed'; let failures = 0; let openedAt = 0;
const THRESHOLD = 5; const COOLDOWN = 30000;
export function canSend(){
  if (state === 'open'){ if (Date.now()-openedAt > COOLDOWN){ state='half'; return true; } return false; }
  return true; // closed or half (single probe)
}
export function onSuccess(){ failures = 0; state = 'closed'; }
export function onFailure(){ failures++; if (state==='half' || failures>=THRESHOLD){ state='open'; openedAt=Date.now(); failures=0; } }
export const breakerState = () => state;

let tokens = 60; const MAX = 60; const REFILL_MS = 1000; // ~1 retry/sec sustained
setInterval(() => { tokens = Math.min(MAX, tokens + 1); }, REFILL_MS);
export function takeToken(){ if (tokens <= 0) return false; tokens--; return true; }

import { canSend, onSuccess, onFailure, breakerState } from './breaker';
import { takeToken } from './budget';
export async function drain(){
  const items = (await queue.all()).sort((a,b)=> priority(b)-priority(a)); // trip-end first
  for (const item of items){
    if (!canSend()){ scheduleProbe(); return; }     // breaker open -> stop, schedule probe
    if (!takeToken()){ setTimeout(drain, 1000); return; } // out of budget -> back off
    try { await api.send(item); await queue.remove(item.id); onSuccess(); }
    catch { onFailure(); if (breakerState()==='open'){ scheduleProbe(); return; } }
  }
}
function priority(i){ return i.type === 'trip_end' ? 2 : i.type === 'trip_start' ? 1 : 0; }
function scheduleProbe(){ setTimeout(drain, 30000); }

// IndexedDB-backed queue; items survive while breaker is open (no loss)
export const queue = {
  all: () => idb.getAll('queue'),
  remove: (id) => idb.delete('queue', id),
  add: (item) => idb.add('queue', { ...item, at: Date.now() }),
};

