export async function ensureScope(db, api, wsId){
  const meta = await db.get('scopes', wsId);
  if (meta?.synced){ await db.put('scopes', { ...meta, lastUsed: Date.now() }); return; }
  let cursor = meta?.cursor || 0;
  for (;;){
    const { items, nextCursor, done } = await api.get(`/workspaces/${wsId}/delta?cursor=${cursor}`);
    const tx = db.transaction(['items','scopes'],'readwrite');
    for (const i of items) await tx.objectStore('items').put({ ...i, scope: wsId });
    await tx.objectStore('scopes').put({ id: wsId, cursor: nextCursor, synced: done, pinned: meta?.pinned||false, lastUsed: Date.now() });
    await tx.done; cursor = nextCursor; if (done) break;
  }
}

import { ensureScope } from './scopes';
import { evictScopes } from './evict';
export async function switchWorkspace(db, api, wsId){
  await evictScopes(db, wsId);      // make room before syncing the new scope
  await ensureScope(db, api, wsId); // sync only this scope
  return loadActive(db, wsId);
}

export async function evictScopes(db, keepActive){
  const { usage, quota } = await navigator.storage.estimate();
  if ((usage||0) < (quota||Infinity) * 0.7) return;
  const scopes = (await db.getAll('scopes')).filter(s => !s.pinned && s.id !== keepActive).sort((a,b)=>a.lastUsed-b.lastUsed);
  for (const s of scopes){
    const tx = db.transaction(['items','scopes'],'readwrite');
    let cur = await tx.objectStore('items').index('scope').openCursor(s.id);
    while (cur){ await cur.delete(); cur = await cur.continue(); }
    await tx.objectStore('scopes').put({ ...s, synced:false, cursor:0 }); // re-syncable later
    await tx.done;
    const est = await navigator.storage.estimate(); if ((est.usage||0) < (est.quota||Infinity)*0.6) break;
  }
}
